    41	  useEffect(() => {
    42	    if (!initialized.current) {
    43	      const initial: Record<string, SyncHealthStatus> = {};
    44	      connectors.forEach(connector => {
    45	        initial[connector.id] = connector.status;
    46	      });
    47	      seen.current = initial;
    48	      initialized.current = true;
